from django.db import models

class Gentercer(models.Model):
    # Clave primaria probable basada en OID
    oid = models.AutoField(db_column='OID', primary_key=True)
    
    # Identificación
    ternumdoc = models.CharField(db_column='TERNUMDOC', max_length=30, blank=True, null=True, verbose_name="Número Documento")
    tertipdoc = models.IntegerField(db_column='TERTIPDOC', blank=True, null=True, verbose_name="Tipo Documento")
    terdigito = models.IntegerField(db_column='TERDIGITO', blank=True, null=True)
    terexpedi = models.CharField(db_column='TEREXPEDI', max_length=50, blank=True, null=True)
    
    # Nombres y Apellidos
    terprinom = models.CharField(db_column='TERPRINOM', max_length=100, blank=True, null=True, verbose_name="Primer Nombre")
    tersegnom = models.CharField(db_column='TERSEGNOM', max_length=100, blank=True, null=True, verbose_name="Segundo Nombre")
    terpriape = models.CharField(db_column='TERPRIAPE', max_length=100, blank=True, null=True, verbose_name="Primer Apellido")
    tersegape = models.CharField(db_column='TERSEGAPE', max_length=100, blank=True, null=True, verbose_name="Segundo Apellido")
    
    # Datos de Ubicación/Otros
    dgnmunicipio = models.CharField(db_column='DGNMUNICIPIO', max_length=50, blank=True, null=True)
    ternacion = models.CharField(db_column='TERNACION', max_length=50, blank=True, null=True)
    tertipper = models.IntegerField(db_column='TERTIPPER', blank=True, null=True)
    tertipret = models.IntegerField(db_column='TERTIPRET', blank=True, null=True)
    tertipcon = models.IntegerField(db_column='TERTIPCON', blank=True, null=True)
    termanica = models.BooleanField(db_column='TERMANICA', blank=True, null=True)
    terporica = models.DecimalField(db_column='TERPORICA', max_digits=18, decimal_places=4, blank=True, null=True)
    termantop = models.BooleanField(db_column='TERMANTOP', blank=True, null=True)
    tervaltop = models.DecimalField(db_column='TERVALTOP', max_digits=18, decimal_places=4, blank=True, null=True)
    tertipo = models.IntegerField(db_column='TERTIPO', blank=True, null=True)
    tercodciu = models.CharField(db_column='TERCODCIU', max_length=20, blank=True, null=True)
    tertipemp = models.IntegerField(db_column='TERTIPEMP', blank=True, null=True)
    tertipent = models.IntegerField(db_column='TERTIPENT', blank=True, null=True)
    tercodent = models.CharField(db_column='TERCODENT', max_length=20, blank=True, null=True)
    terporret = models.DecimalField(db_column='TERPORRET', max_digits=18, decimal_places=4, blank=True, null=True)
    terresolu = models.CharField(db_column='TERRESOLU', max_length=50, blank=True, null=True)
    teraretica = models.BooleanField(db_column='TERARETICA', blank=True, null=True)
    teraretiva = models.BooleanField(db_column='TERARETIVA', blank=True, null=True)
    terprocesa = models.BooleanField(db_column='TERPROCESA', blank=True, null=True)
    
    # Campos adicionales
    tercodpais = models.CharField(db_column='TERCODPAIS', max_length=20, blank=True, null=True)
    tertipotro = models.BooleanField(db_column='TERTIPOTRO', blank=True, null=True)
    tertipclie = models.BooleanField(db_column='TERTIPCLIE', blank=True, null=True)
    tertipprov = models.BooleanField(db_column='TERTIPPROV', blank=True, null=True)
    tertipempl = models.BooleanField(db_column='TERTIPEMPL', blank=True, null=True)
    tertipcont = models.BooleanField(db_column='TERTIPCONT', blank=True, null=True)
    tertippens = models.BooleanField(db_column='TERTIPPENS', blank=True, null=True)
    terdocfox = models.CharField(db_column='TERDOCFOX', max_length=50, blank=True, null=True)
    tercodita = models.CharField(db_column='TERCODITA', max_length=50, blank=True, null=True)
    teractinac = models.BooleanField(db_column='TERACTINAC', blank=True, null=True)
    textwidth = models.CharField(db_column='TERNOMCOM', max_length=255, blank=True, null=True, verbose_name="Nombre Completo")

    class Meta:
        managed = True
        db_table = 'GENTERCER'
        verbose_name = 'Terceros (GENTERCER)'

    def __str__(self):
        doc = self.ternumdoc or "S/D"
        nombre = f"{self.terprinom or ''} {self.tersegnom or ''} {self.terpriape or ''} {self.tersegape or ''}".strip()
        return f"{doc} - {nombre}"

